192 bool ConstraintSystem::mayHaveSolution() {
193   LLVM_DEBUG(dbgs() << "---\n");
194   LLVM_DEBUG(dump());
195   bool HasSolution = mayHaveSolutionImpl();
196   LLVM_DEBUG(dbgs() << (HasSolution ? "sat" : "unsat") << "\n");
197   return HasSolution;
198 }
